import{c as a,Q as r,j as t,m as o}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Model-Harness Fit","description":"","frontmatter":{"url":"https://nicolasbustamante.com/blog/model-harness-fit","title":"Model-Harness Fit","author":"Nicolas Bustamante","archived":"2026-05-16T00:00:00.000Z","domain":"nicolasbustamante.com","published":"未知","tags":["model-harness","agent","claude-code","codex","copilot","post-training"],"word_count":"約 620 字"},"headers":[],"relativePath":"research/ai-articles/2026-05-16-model-harness-fit.md","filePath":"research/ai-articles/2026-05-16-model-harness-fit.md","lastUpdated":1779894392000}'),s={name:"research/ai-articles/2026-05-16-model-harness-fit.md"};function n(i,e,c,l,d,h){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="model-harness-fit" tabindex="-1">Model-Harness Fit <a class="header-anchor" href="#model-harness-fit" aria-label="Permalink to &quot;Model-Harness Fit&quot;">​</a></h1><blockquote><p><strong>來源</strong>：<a href="https://nicolasbustamante.com/blog/model-harness-fit" target="_blank" rel="noreferrer">nicolasbustamante.com</a><br><strong>作者</strong>：Nicolas Bustamante<br><strong>發布日期</strong>：未知<br><strong>收錄日期</strong>：2026-05-16<br><strong>字數</strong>：約 620 字</p></blockquote><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Nicolas Bustamante 的文章探討為何在不同 agent harness（協作框架）之間切換模型，即使使用相同的模型權重，性能也會下降。核心論點：<strong>模型是針對特定 harness 進行 post-training 的，因此配對（model + harness）才是正確的分析單位，而非模型本身。</strong></p><h2 id="core-argument" tabindex="-1">Core Argument <a class="header-anchor" href="#core-argument" aria-label="Permalink to &quot;Core Argument&quot;">​</a></h2><p>Bustamante 論證「模型是針對 harness 而非僅針對 API 進行 post-training」。Tool 名稱、input schemas、引用慣例、system prompt 結構都是「baked into post training 的 byte-level 慣例」。將模型從其原生 harness 抽出，所損失的性能「不重寫任何一側就無法找回」。</p><h2 id="evidence-from-terminal-bench-2-0" tabindex="-1">Evidence from Terminal-Bench 2.0 <a class="header-anchor" href="#evidence-from-terminal-bench-2-0" aria-label="Permalink to &quot;Evidence from Terminal-Bench 2.0&quot;">​</a></h2><p>排行榜揭示顯著差距：Claude Opus 4.6 搭配 ForgeCode 達到 79.8%，但搭配 Capy 只有 75.3%——<strong>相同模型、不同 harness，差距 4.5 個百分點</strong>。Cursor 研究團隊回報「僅改變 harness，就從 Top 30 躍升至 Top 5」。</p><h2 id="three-harness-architectures-compared" tabindex="-1">Three Harness Architectures Compared <a class="header-anchor" href="#three-harness-architectures-compared" aria-label="Permalink to &quot;Three Harness Architectures Compared&quot;">​</a></h2><p><strong>Codex CLI</strong>：使用帶有結構化記憶提取的 typed 非同步 submission/event queue，透過嚴格 JSON schema 與 <code>&lt;oai-mem-citation&gt;</code> 標籤實現 decay signals。</p><p><strong>Claude Code</strong>：直接對話迴圈，使用 <code>Read</code>/<code>Edit</code>/<code>Write</code> 工具進行同步 file-based 記憶寫入，並透過 <code>&lt;system-reminder&gt;</code> 注入。</p><p><strong>GitHub Copilot CLI</strong>：透過 JSON RPC subprocess 執行 supervisor protocol，搭配 server-side 記憶後端與 <code>store_memory</code> 工具。</p><h2 id="divergent-tool-surfaces" tabindex="-1">Divergent Tool Surfaces <a class="header-anchor" href="#divergent-tool-surfaces" aria-label="Permalink to &quot;Divergent Tool Surfaces&quot;">​</a></h2><p>每個 harness 提供不同的 tool vocabulary：Codex 提供帶有 Lark grammar 的 <code>apply_patch</code>；Claude Code 使用帶有 <code>old_string</code>/<code>new_string</code> 替換的 <code>Edit</code>；Copilot CLI 依照當前模型路由兩者。<strong>相同的概念操作有「不同的 shape」</strong>，要求在一個 surface 上訓練的模型在切換時必須脫離其本能集合外運作。</p><h2 id="the-memory-layer-problem" tabindex="-1">The Memory Layer Problem <a class="header-anchor" href="#the-memory-layer-problem" aria-label="Permalink to &quot;The Memory Layer Problem&quot;">​</a></h2><p>引用機制存在根本差異：Codex 的 <code>&lt;oai-mem-citation&gt;</code> blocks 在 SQLite 中遞增 <code>usage_count</code> 以驅動 decay 邏輯；Claude Code 的模型透過帶有 age-in-days 標注的 <code>&lt;system-reminder&gt;</code> wrappers 讀取記憶；Copilot CLI 委派給遠端伺服器。跨 harness 執行會導致記憶系統「靜默失敗或執行降級版本」。</p><h2 id="system-prompt-structure" tabindex="-1">System Prompt Structure <a class="header-anchor" href="#system-prompt-structure" aria-label="Permalink to &quot;System Prompt Structure&quot;">​</a></h2><p>Copilot CLI 文件化了十個明確的 system prompt section IDs（<code>identity</code>、<code>tone</code>、<code>tool_efficiency</code> 等）。每個區塊帶有特定的 authority weight——<code>safety</code> 區塊比 <code>guidelines</code> 更硬性。在不同 prompt 排序下訓練的模型，對指令優先序的處理方式不同。</p><h2 id="key-insight-the-matched-pair" tabindex="-1">Key Insight: The Matched Pair <a class="header-anchor" href="#key-insight-the-matched-pair" aria-label="Permalink to &quot;Key Insight: The Matched Pair&quot;">​</a></h2><p>正如 LangChain 的 Trivedy 所言：「Agent = Model + Harness。如果你不是模型，你就是 harness。」Cursor 的 Stefan Heule 描述這份工作是「執念地堆疊小優化」，因為「step change 很罕見，收益只在匹配的 pair 內複合累積」。</p><h2 id="practical-implications" tabindex="-1">Practical Implications <a class="header-anchor" href="#practical-implications" aria-label="Permalink to &quot;Practical Implications&quot;">​</a></h2><ul><li><strong>平台建構者</strong>：以統一產品出貨 model-harness pairs，而非模組化元件</li><li><strong>模型實驗室</strong>：harness 代表產品策略與競爭護城河，而非單純基礎設施</li><li><strong>使用者</strong>：mid-conversation 切換模型會同時破壞對話歷史分佈、cache 結構與 tool surfaces</li><li><strong>關鍵不穩定性</strong>：隨著模型成熟，harness 元件會變得 load-bearing 或過時——Rajasekaran 的工作顯示，Sonnet 4.5 所需的 context-reset 機制對 Opus 4.6 已不必要</li></ul><h2 id="strategic-convergence" tabindex="-1">Strategic Convergence <a class="header-anchor" href="#strategic-convergence" aria-label="Permalink to &quot;Strategic Convergence&quot;">​</a></h2><p>Anthropic 出貨 Claude Code 作為 canonical Claude harness；OpenAI 出貨 Codex CLI 作為 canonical Codex harness；GitHub 出貨帶有明確 per-model routing 的 Copilot CLI 應對多模型場景。每個都代表對 model-harness coupling 管理的一個連貫但不同的答案。</p>',25)])])}const u=a(s,[["render",n]]);export{p as __pageData,u as default};
